const body = $json.body;
const status = body.status;
const bogOrderId = body.order_id;
const amount = body.amount;
const currency = body.currency || 'GEL';
const failureReason = body.failure_reason;

let action = 'unknown';

switch(status) {
  case 'completed':
    action = 'activate';
    break;
  case 'failed':
    action = 'failed';
    break;
  case 'expired':
    action = 'expired';
    break;
  case 'pending':
    action = 'pending';
    break;
  default:
    action = 'unknown';
}

return [{
  json: {
    orderId: bogOrderId,
    action,
    status,
    amount,
    currency,
    failureReason,
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

const data = $json;

if (data.action === 'activate') {
  return [{
    json: {
      status: 'completed',
      completed_at: new Date().toISOString(),
      failure_reason: null
    }
  }];
} else if (data.action === 'failed') {
  return [{
    json: {
      status: 'failed',
      failure_reason: data.failureReason || 'Payment failed'
    }
  }];
} else if (data.action === 'expired') {
  return [{
    json: {
      status: 'expired',
      failure_reason: 'Order expired'
    }
  }];
}

return [];

const action = $json.action;
if (action === 'failed' || action === 'expired') {
  return [{
    json: {
      sendRecovery: true,
      delayHours: 72
    }
  }];
}
return [];
